public int[] shiftLeft(int[] nums) {
    if (nums == null || nums.length == 0) {
        return nums;
    }

    int temp = nums[0];
    for (int i = 0; i < nums.length - 1; i++) {
        nums[i] = nums[i + 1];
    }
    nums[nums.length - 1] = temp;
    return nums;
}

java
public int[] shiftLeft(int[] nums) {
    if (nums == null || nums.length == 0) {
        return nums;
    }

    int[] newArr = new int[nums.length];
    for (int i = 0; i < nums.length - 1; i++) {
        newArr[i] = nums[i + 1];
    }
    newArr[nums.length - 1] = nums[0];
    return newArr;
}

